import type { Metadata } from 'next';
import { setRequestLocale } from 'next-intl/server';
import { notFound } from 'next/navigation';
import { compileMDX } from 'next-mdx-remote/rsc';
import type { JSX } from 'react';

import { supportedLocales, type Locale } from '@bimdossier/i18n';

import { BlogPostCoverImage } from '@/components/blog/BlogPostCoverImage';
import { BlogPostHero } from '@/components/blog/BlogPostHero';
import { mdxComponents } from '@/components/blog/MdxComponents';
import { getAllSlugs, getPostBySlugMerged } from '@/lib/blog/mdx';

// API-published posts must be reachable, so allow params outside the
// `generateStaticParams` set to render on-demand and be cached for 60s.
export const dynamicParams = true;
export const revalidate = 60;

type Params = { locale: string; slug: string };

export function generateStaticParams(): Params[] {
  return supportedLocales.flatMap((locale) =>
    getAllSlugs(locale).map((slug) => ({ locale, slug })),
  );
}

export async function generateMetadata({
  params,
}: {
  params: Promise<Params>;
}): Promise<Metadata> {
  const { locale, slug } = await params;
  const post = await getPostBySlugMerged(slug, locale as Locale);
  if (post === null) {
    // Bare title — the [locale]/layout.tsx `%s — BimDossier` template appends
    // the suffix, so adding it here would double it.
    return { title: 'Post not found' };
  }
  return {
    title: post.meta.title,
    description: post.meta.description,
    openGraph: {
      title: post.meta.title,
      description: post.meta.description,
      type: 'article',
      publishedTime: post.meta.date,
      authors: [post.meta.author],
      tags: post.meta.tags,
      ...(post.meta.image ? { images: [post.meta.image] } : {}),
    },
  };
}

export default async function BlogPostPage({
  params,
}: {
  params: Promise<Params>;
}): Promise<JSX.Element> {
  const { locale, slug } = await params;
  setRequestLocale(locale);

  const post = await getPostBySlugMerged(slug, locale as Locale);
  if (post === null) {
    notFound();
  }

  const { content: mdxContent } = await compileMDX({
    source: post.content,
    components: mdxComponents,
  });

  const jsonLd = {
    '@context': 'https://schema.org',
    '@type': 'BlogPosting',
    headline: post.meta.title,
    description: post.meta.description,
    datePublished: post.meta.date,
    author: {
      '@type': 'Organization',
      name: post.meta.author,
    },
  };

  return (
    <main>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
      <BlogPostHero meta={post.meta} locale={locale} />
      {post.meta.image ? (
        <div className="mx-auto w-full max-w-8xl px-6 pt-12">
          <BlogPostCoverImage image={post.meta.image} title={post.meta.title} />
        </div>
      ) : null}
      <div className="mx-auto w-full max-w-8xl px-6 pb-12 pt-8">
        <article className="prose prose-neutral max-w-none dark:prose-invert [&>h2]:mt-10 [&>h2]:text-h4 [&>h2]:font-semibold [&>h3]:mt-8 [&>h3]:text-title2 [&>h3]:font-semibold [&>p]:text-body1 [&>p]:text-foreground-secondary [&>p]:leading-relaxed [&>ul]:text-body1 [&>ul]:text-foreground-secondary [&>ol]:text-body1 [&>ol]:text-foreground-secondary">
          {mdxContent}
        </article>
      </div>
    </main>
  );
}

'use client';

import { useTranslations } from 'next-intl';
import type { JSX } from 'react';

import { Button } from '@bimdossier/ui';
import { ArrowRight, CalendarClock, Mail } from '@bimdossier/ui/icons';

import { HeroPill } from '@/components/sections/HeroPill';
import { HeroShell } from '@/components/sections/HeroShell';
import { Link } from '@/i18n/navigation';
import { env } from '@/lib/env';

export function ContactSalesClient(): JSX.Element {
  const t = useTranslations('contactPage');
  const tHeader = useTranslations('header');
  const bookingUrl = env.NEXT_PUBLIC_CONTACT_BOOKING_URL;
  const contactEmail = env.NEXT_PUBLIC_CONTACT_EMAIL;

  return (
    <>
      <HeroShell size="splash" align="center" className="max-w-3xl gap-4">
        <HeroPill>{t('eyebrow')}</HeroPill>
        <h1 className="max-w-2xl text-h3 font-semibold text-white sm:text-h2">
          {t('headline')}
        </h1>
        <p className="max-w-xl text-title3 text-white/80">{t('subtitle')}</p>
      </HeroShell>

      <section className="mx-auto w-full max-w-3xl px-6 py-16">
        <div className="grid gap-8 sm:grid-cols-2">
          <div className="flex flex-col gap-4 rounded-xl border border-border bg-surface-low p-6">
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary-lighter">
              <CalendarClock className="h-5 w-5 text-primary" />
            </div>
            <h2 className="text-title2 font-semibold text-foreground">
              {t('bookCall')}
            </h2>
            <p className="text-body2 text-foreground-secondary">
              {t('bookCallDescription')}
            </p>
            {bookingUrl ? (
              <a href={bookingUrl} target="_blank" rel="noopener noreferrer" className="mt-auto">
                <Button variant="primary" size="md" className="w-full">
                  {t('bookCall')}
                  <ArrowRight className="ml-1.5 h-4 w-4" />
                </Button>
              </a>
            ) : (
              <p className="mt-auto text-body3 text-foreground-tertiary">
                {t('noBookingUrl')}
              </p>
            )}
          </div>

          <div className="flex flex-col gap-4 rounded-xl border border-border bg-surface-low p-6">
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary-lighter">
              <Mail className="h-5 w-5 text-primary" />
            </div>
            <h2 className="text-title2 font-semibold text-foreground">
              {t('orEmail')}
            </h2>
            <p className="text-body2 text-foreground-secondary">
              {t('emailDescription')}
            </p>
            {contactEmail ? (
              <a href={`mailto:${contactEmail}`} className="mt-auto">
                <Button variant="border" size="md" className="w-full">
                  {t('emailButton')}
                  <Mail className="ml-1.5 h-4 w-4" />
                </Button>
              </a>
            ) : (
              <Link href="/request-access" className="mt-auto">
                <Button variant="border" size="md" className="w-full">
                  {tHeader('requestAccess')}
                  <ArrowRight className="ml-1.5 h-4 w-4" />
                </Button>
              </Link>
            )}
          </div>
        </div>
      </section>
    </>
  );
}

import type { Metadata } from 'next';
import { setRequestLocale } from 'next-intl/server';
import { notFound } from 'next/navigation';
import type { JSX } from 'react';

import { supportedLocales } from '@bimdossier/i18n';

import { FeatureBody } from '@/components/features/FeatureBody';
import { FeatureFaq } from '@/components/features/FeatureFaq';
import { FeatureHero } from '@/components/features/FeatureHero';
import { FeatureHighlights } from '@/components/features/FeatureHighlights';
import { FeatureImages } from '@/components/features/FeatureImages';
import { FeatureRelated } from '@/components/features/FeatureRelated';
import { FEATURE_SLUGS, getFeatureContent } from '@/components/features/featureContent';

// The 12 feature slugs are fully known at build time, so anything outside the
// generated set should hard-404 (no on-demand rendering, unlike the blog).
export const dynamicParams = false;

type Params = { locale: string; slug: string };

export function generateStaticParams(): Params[] {
  return supportedLocales.flatMap((locale) =>
    FEATURE_SLUGS.map((slug) => ({ locale, slug })),
  );
}

export async function generateMetadata({
  params,
}: {
  params: Promise<Params>;
}): Promise<Metadata> {
  const { locale, slug } = await params;
  const content = getFeatureContent(slug, locale);
  if (content === null) {
    return { title: 'Feature not found — BimDossier' };
  }
  const { title, intro: description, keywords } = content;

  return {
    // The locale layout supplies the `%s — BimDossier` title template, so the
    // bare feature title is enough — avoids a doubled suffix.
    title,
    description,
    keywords,
    openGraph: {
      title: `${title} — BimDossier`,
      description,
      type: 'website',
    },
    twitter: {
      card: 'summary_large_image',
      title: `${title} — BimDossier`,
      description,
    },
  };
}

export default async function FeaturePage({
  params,
}: {
  params: Promise<Params>;
}): Promise<JSX.Element> {
  const { locale, slug } = await params;
  setRequestLocale(locale);

  const content = getFeatureContent(slug, locale);
  if (content === null) {
    notFound();
  }

  // Build the FAQPage structured data server-side so it ships in the SSR HTML
  // (Google rich-result eligible). Same pattern as the blog post page.
  const jsonLd = {
    '@context': 'https://schema.org',
    '@type': 'FAQPage',
    mainEntity: content.faq.map((item) => ({
      '@type': 'Question',
      name: item.q,
      acceptedAnswer: {
        '@type': 'Answer',
        text: item.a,
      },
    })),
  };

  return (
    <main>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
      <FeatureHero featureKey={slug} />
      <FeatureBody featureKey={slug} />
      <FeatureHighlights featureKey={slug} />
      <FeatureFaq featureKey={slug} />
      <FeatureImages featureKey={slug} />
      <FeatureRelated featureKey={slug} />
    </main>
  );
}

import type { Metadata } from 'next';
import { hasLocale, NextIntlClientProvider } from 'next-intl';
import { getTranslations, setRequestLocale } from 'next-intl/server';
import { Fraunces } from 'next/font/google';
import { notFound } from 'next/navigation';
import type { JSX, ReactNode } from 'react';

import { routing } from '@/i18n/routing';
import { PostHogProvider } from '@/providers/PostHogProvider';
import { ThemeProvider } from '@/providers/ThemeProvider';

const fraunces = Fraunces({
  subsets: ['latin'],
  variable: '--font-display',
  weight: ['400', '500', '600'],
  display: 'swap',
});

export function generateStaticParams(): Array<{ locale: string }> {
  return routing.locales.map((locale) => ({ locale }));
}

type Props = {
  children: ReactNode;
  params: Promise<{ locale: string }>;
};

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: string }>;
}): Promise<Metadata> {
  const { locale } = await params;
  const t = await getTranslations({ locale, namespace: 'metadata' });
  return {
    title: {
      default: t('defaultTitle'),
      template: '%s — BimDossier',
    },
    description: t('description'),
    openGraph: {
      type: 'website',
      siteName: 'BimDossier',
      title: t('defaultTitle'),
      description: t('description'),
      locale: locale === 'nl' ? 'nl_NL' : 'en_US',
    },
    twitter: {
      card: 'summary_large_image',
      title: t('title'),
      description: t('description'),
    },
    alternates: {
      types: {
        'application/rss+xml': '/feed.xml',
      },
    },
  };
}

export default async function LocaleLayout({ children, params }: Props): Promise<JSX.Element> {
  const { locale } = await params;
  if (!hasLocale(routing.locales, locale)) {
    notFound();
  }
  setRequestLocale(locale);

  return (
    <html lang={locale} className={fraunces.variable} suppressHydrationWarning>
      <body className="min-h-screen bg-background text-foreground antialiased">
        <NextIntlClientProvider>
          <ThemeProvider>
            <PostHogProvider>{children}</PostHogProvider>
          </ThemeProvider>
        </NextIntlClientProvider>
      </body>
    </html>
  );
}

import type { JSX } from 'react';

import type { LegalDocument } from '@bimdossier/i18n';

type Props = {
  doc: LegalDocument;
  lastUpdatedLabel: string;
  draftBanner?: string;
};

export function LegalArticle({ doc, lastUpdatedLabel, draftBanner }: Props): JSX.Element {
  const dateLabel = lastUpdatedLabel.replace('{date}', doc.lastUpdated);

  return (
    <div className="flex flex-col gap-6">
      {draftBanner ? (
        <div className="rounded-md border border-warning-light bg-warning-lighter px-4 py-3 text-body2 text-warning">
          {draftBanner}
        </div>
      ) : null}
      <article className="space-y-8">
        <header className="space-y-3">
          <h1 className="m-0 font-sans text-h4 font-medium leading-tight tracking-tight text-foreground">
            {doc.title}
          </h1>
          <p className="font-sans text-caption uppercase tracking-[0.10em] text-foreground-tertiary">
            {dateLabel}
          </p>
          <p className="text-body1 leading-relaxed text-foreground-secondary">{doc.intro}</p>
        </header>

        {doc.sections.map((section) => (
          <section key={section.title} className="space-y-2">
            <h2 className="font-sans text-title3 font-semibold leading-tight tracking-tight text-foreground">
              {section.title}
            </h2>
            <p className="text-body2 leading-relaxed text-foreground-secondary">{section.body}</p>
          </section>
        ))}
      </article>
    </div>
  );
}

import { setRequestLocale } from 'next-intl/server';
import type { JSX } from 'react';

import { getLegalContent, type Locale } from '@bimdossier/i18n';

import { LegalArticle } from '../LegalArticle';

type Props = {
  params: Promise<{ locale: string }>;
};

export default async function DpaPage({ params }: Props): Promise<JSX.Element> {
  const { locale } = await params;
  setRequestLocale(locale);
  const { dpa, meta } = getLegalContent(locale as Locale);

  return (
    <LegalArticle doc={dpa} lastUpdatedLabel={meta.lastUpdatedLabel} draftBanner={meta.draftBanner} />
  );
}

import { setRequestLocale } from 'next-intl/server';
import type { JSX } from 'react';

import { getLegalContent, type Locale } from '@bimdossier/i18n';

import { LegalArticle } from '../LegalArticle';

type Props = {
  params: Promise<{ locale: string }>;
