import type { JSX } from 'react';

import { HeroGrid } from '@bimdossier/brand';

import { RemoteOrLocalImage } from './RemoteOrLocalImage';

type BlogCardThumbnailProps = {
  slug: string;
  image?: string | undefined;
  title: string;
};

const GRADIENTS = [
  'from-[var(--brand-gradient-start)] to-[var(--brand-gradient-end)]',
  'from-[var(--brand-gradient-end)] to-[var(--brand-gradient-start)]',
  'from-[var(--brand-gradient-start)] to-[var(--primary-dark,var(--brand-gradient-end))]',
  'from-[var(--brand-gradient-end)] via-[var(--brand-gradient-start)] to-[var(--brand-gradient-end)]',
  'from-[var(--brand-gradient-start)] via-[var(--brand-gradient-end)] to-[var(--brand-gradient-start)]',
];

function hashSlug(slug: string): number {
  let hash = 0;
  for (let i = 0; i < slug.length; i++) {
    hash = (hash * 31 + slug.charCodeAt(i)) | 0;
  }
  return Math.abs(hash);
}

export function BlogCardThumbnail({
  slug,
  image,
  title,
}: BlogCardThumbnailProps): JSX.Element {
  if (image) {
    return (
      <div className="relative aspect-[16/10] w-full">
        <RemoteOrLocalImage src={image} alt={title} sizes="(max-width: 640px) 100vw, 50vw" />
      </div>
    );
  }

  const idx = hashSlug(slug) % GRADIENTS.length;
  const gradient = GRADIENTS[idx];

  return (
    <div
      className={`relative aspect-[16/10] w-full bg-gradient-to-br ${gradient}`}
    >
      <HeroGrid opacity={0.1} stroke="#ffffff" step={28} />
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_60%_80%_at_70%_30%,rgba(95,217,158,0.12),transparent)]" />
    </div>
  );
}

import type { MDXComponents } from 'mdx/types';
import type { AnchorHTMLAttributes, HTMLAttributes, JSX } from 'react';

function slugify(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '');
}

function heading(Tag: 'h2' | 'h3' | 'h4') {
  return function MdxHeading(
    { children, ...rest }: HTMLAttributes<HTMLHeadingElement>,
  ): JSX.Element {
    const text = typeof children === 'string' ? children : '';
    const id = slugify(text);
    return (
      <Tag {...rest} id={id} className="scroll-mt-24">
        <a href={`#${id}`} className="no-underline hover:underline">
          {children}
        </a>
      </Tag>
    );
  };
}

export const mdxComponents: MDXComponents = {
  h2: heading('h2'),
  h3: heading('h3'),
  h4: heading('h4'),
  a: (props: AnchorHTMLAttributes<HTMLAnchorElement>) => {
    const { href } = props;
    // eslint-disable-next-line @typescript-eslint/prefer-optional-chain
    const isExternal = href != null
      && href.startsWith('http');
    return (
      <a
        {...props}
        className="text-primary underline decoration-primary underline-offset-2"
        target={isExternal ? '_blank' : undefined}
        rel={isExternal ? 'noopener noreferrer' : undefined}
      />
    );
  },
  blockquote: (props: HTMLAttributes<HTMLQuoteElement>) => (
    <blockquote
      {...props}
      className="border-l-4 border-primary-light bg-surface-low pl-4 italic text-foreground-secondary [&>p]:my-2"
    />
  ),
  table: (props: HTMLAttributes<HTMLTableElement>) => (
    <div className="overflow-x-auto">
      <table
        {...props}
        className="w-full border-collapse text-body2 [&_td]:border [&_td]:border-border [&_td]:px-3 [&_td]:py-2 [&_th]:border [&_th]:border-border [&_th]:bg-surface-low [&_th]:px-3 [&_th]:py-2 [&_th]:text-left [&_th]:font-semibold"
      />
    </div>
  ),
  pre: (props: HTMLAttributes<HTMLPreElement>) => (
    <pre
      {...props}
      className="overflow-x-auto rounded-lg border border-border bg-surface-low p-4 text-body3"
    />
  ),
  code: (props: HTMLAttributes<HTMLElement>) => {
    const isInline = typeof props.children === 'string' && !props.className;
    if (isInline) {
      return (
        <code className="rounded bg-surface-low px-1.5 py-0.5 text-body3 text-foreground">
          {props.children}
        </code>
      );
    }
    return <code {...props} />;
  },
};

import Image from 'next/image';
import type { JSX } from 'react';

type RemoteOrLocalImageProps = {
  src: string;
  alt: string;
  sizes: string;
  priority?: boolean;
};

/**
 * Cover image that picks the right element by URL kind. Absolute http(s) URLs
 * (presigned MinIO/S3 covers from API-published posts) use a plain `<img>`
 * because next/image rejects domains not declared in `remotePatterns`; local
 * `/public` paths go through next/image (`<Image fill>`). The caller provides
 * the positioned wrapper (it owns aspect ratio / rounding).
 */
export function RemoteOrLocalImage({
  src,
  alt,
  sizes,
  priority = false,
}: RemoteOrLocalImageProps): JSX.Element {
  const isRemote = /^https?:\/\//i.test(src);
  if (isRemote) {
    // eslint-disable-next-line @next/next/no-img-element
    return <img src={src} alt={alt} className="absolute inset-0 h-full w-full object-cover" />;
  }
  return <Image src={src} alt={alt} fill priority={priority} className="object-cover" sizes={sizes} />;
}

