'use client';

import { Button, Eyebrow } from '@bimdossier/ui';
import { useTranslations } from 'next-intl';
import dynamic from 'next/dynamic';
import { useEffect, useState, type JSX } from 'react';

import { useInView } from '@/hooks/useInView';
import { useReducedMotion } from '@/hooks/useReducedMotion';
import { Link } from '@/i18n/navigation';

import { DEMO_SNAGS, type DemoSnagSeverity } from './snag-showcase/demoSnags';

const SnagViewer = dynamic(() => import('./snag-showcase/SnagViewer'), {
  ssr: false,
  loading: () => <ShowcaseSkeleton />,
});

const SEVERITY_DOT: Record<DemoSnagSeverity, string> = {
  high: 'bg-error',
  medium: 'bg-warning',
  low: 'bg-info',
};

function hasWebGL(): boolean {
  try {
    const canvas = document.createElement('canvas');
    return Boolean(
      window.WebGLRenderingContext &&
        (canvas.getContext('webgl2') || canvas.getContext('webgl')),
    );
  } catch {
    return false;
  }
}

function ShowcaseSkeleton(): JSX.Element {
  // Match the section's bg so the transparent viewer canvas blends seamlessly —
  // surface-medium showed through the alpha:0 canvas as an off-color rectangle.
  // `z-10` keeps it ON TOP of the (transparent) canvas while the model loads and
  // frames, so the built-in zoom-extents excursion is never seen — the model is
  // revealed (via the fade below) only once it's already framed.
  return <div className="absolute inset-0 z-10 animate-pulse bg-surface-low" aria-hidden />;
}

function ShowcaseFallback(): JSX.Element {
  const t = useTranslations('snagShowcase');
  return (
    <div className="flex h-full w-full flex-col gap-3 overflow-auto p-5">
      <p className="text-body3 font-semibold text-foreground">{t('fallbackTitle')}</p>
      <p className="text-body3 text-foreground-tertiary">{t('fallbackBody')}</p>
      <ul className="mt-1 flex flex-col gap-2">
        {DEMO_SNAGS.map((snag) => (
          <li
            key={snag.id}
            className="flex items-start gap-2 rounded-lg bg-surface-low p-3 ring-1 ring-border"
          >
            <span
              aria-hidden
              className={`mt-1 h-2 w-2 shrink-0 rounded-full ${SEVERITY_DOT[snag.severity]}`}
            />
            <div className="flex flex-col">
              <span className="text-body3 font-medium text-foreground">
                {t(`snags.${snag.titleKey}`)}
              </span>
              <span className="text-caption text-foreground-tertiary">
                {t(`severity.${snag.severity}`)} · Bbl {snag.bblArticleRef}
              </span>
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
}

export function SnagShowcaseSection(): JSX.Element {
  const t = useTranslations('snagShowcase');
  const reducedMotion = useReducedMotion();
  // Start fetching the viewer chunk slightly before the canvas scrolls in.
  const { ref, inView } = useInView<HTMLDivElement>({ rootMargin: '200px', once: true });

  const [webgl, setWebgl] = useState(true);
  const [loaded, setLoaded] = useState(false);
  const [failed, setFailed] = useState(false);

  useEffect(() => {
    setWebgl(hasWebGL());
  }, []);

  return (
    <section id="showcase" className="bg-surface-low">
      {/* Full-bleed hero: the <section> already spans the viewport, so the canvas
          just drops the max-w constraint. Mobile stacks (text above a shorter
          canvas); lg turns the canvas into a full-height backdrop with the text
          overlaid on the left. */}
      <div className="relative flex flex-col lg:block lg:h-[75vh] lg:min-h-[640px] lg:max-h-[860px]">
        {/* CANVAS LAYER */}
        <div
          ref={ref}
          className="relative order-2 h-[55vh] min-h-[340px] w-full lg:order-none lg:absolute lg:inset-0 lg:h-full"
        >
          {!webgl || failed ? (
            <ShowcaseFallback />
          ) : !inView ? (
            <ShowcaseSkeleton />
          ) : (
            <>
              {/* Fade the canvas in only once SnagViewer signals it's framed
                  (onLoaded fires after showcase.zoomIn lands), so the model
                  appears already sized — no load-time pop/zoom. */}
              <div
                className={`h-full w-full transition-opacity duration-700 ${
                  loaded ? 'opacity-100' : 'opacity-0'
                }`}
              >
                <SnagViewer
                  reducedMotion={reducedMotion}
                  onError={() => setFailed(true)}
                  onLoaded={() => setLoaded(true)}
                />
              </div>
              {!loaded && <ShowcaseSkeleton />}
            </>
          )}
        </div>

        {/* SCRIM — desktop only, left half, keeps the overlaid text legible over
            the canvas. from-token → transparent (no opacity-modifier needed). */}
        <div
          aria-hidden
          className="pointer-events-none absolute inset-0 hidden bg-gradient-to-r from-surface-low to-transparent lg:block lg:w-1/2"
        />

        {/* TEXT OVERLAY — click-through except the buttons, so dragging the whole
            canvas still orbits. Aligned to the page content width. */}
        <div className="pointer-events-none order-1 lg:order-none lg:absolute lg:inset-0 lg:z-10">
          <div className="mx-auto flex h-full max-w-8xl items-center px-6 pt-16 pb-10 lg:py-0">
            <div className="flex max-w-md flex-col gap-4">
              <Eyebrow size="sm">{t('eyebrow')}</Eyebrow>
              <h2 className="text-h3 font-semibold text-foreground">{t('headline')}</h2>
              <p className="text-body1 text-foreground-secondary">{t('subtitle')}</p>
              <ul className="flex flex-col gap-2 text-body2 text-foreground-secondary">
                <li className="flex items-center gap-2">
                  <span aria-hidden className="h-1.5 w-1.5 rounded-full bg-primary" />
                  {t('hintDrag')}
                </li>
                <li className="flex items-center gap-2">
                  <span aria-hidden className="h-1.5 w-1.5 rounded-full bg-primary" />
                  {t('hintClick')}
                </li>
              </ul>
              <div className="pointer-events-auto mt-2 flex flex-wrap items-center gap-4">
                <Link href="/request-access">
                  <Button variant="primary" size="lg">
                    {t('cta')}
                  </Button>
                </Link>
                <Link
                  href="/blog"
                  className="text-body2 font-medium text-primary hover:underline"
                >
                  {t('learnMoreBlog')}
                </Link>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

import {
  AlertTriangle,
  Bell,
  Boxes,
  CalendarClock,
  Camera,
  ClipboardCheck,
  FileBadge,
  FileText,
  FolderKanban,
  MapPin,
  MessageSquare,
  ShieldCheck,
  Share2,
  Smartphone,
  Sparkles,
  Users,
  type AppIcon,
} from '@bimdossier/ui/icons';

/**
 * Single source of truth for the marketing feature list. `available` items
 * render in `FeaturesSection`; `coming_soon` items render dimmed in
 * `RoadmapSection`. Promoting a roadmap item to shipped is a one-line `status`
 * flip here (plus moving its copy from `roadmap.items.*` to `features.*` in the
 * message catalogs). Statuses are verified against live code, not the backlog
 * CSV — anything partial/deferred stays in `coming_soon`.
 */
export type FeatureStatus = 'available' | 'coming_soon';

export type FeatureItem = {
  /** i18n key under `features.*` (available) or `roadmap.items.*` (coming_soon). */
  key: string;
  icon: AppIcon;
  status: FeatureStatus;
};

export const FEATURES: FeatureItem[] = [
  // Shipped — verified against code.
  { key: 'deadlines', icon: CalendarClock, status: 'available' },
  { key: 'dossier', icon: ClipboardCheck, status: 'available' },
  { key: 'findings', icon: AlertTriangle, status: 'available' },
  { key: 'snagging', icon: MapPin, status: 'available' },
  { key: 'board', icon: FolderKanban, status: 'available' },
  { key: 'photos', icon: Camera, status: 'available' },
  { key: 'mobile', icon: Smartphone, status: 'available' },
  { key: 'viewer', icon: Boxes, status: 'available' },
  { key: 'certificates', icon: FileBadge, status: 'available' },
  { key: 'reports', icon: FileText, status: 'available' },
  { key: 'bcf', icon: Share2, status: 'available' },
  { key: 'collaboration', icon: Users, status: 'available' },
  // Roadmap — verified NOT shipped.
  { key: 'comments', icon: MessageSquare, status: 'coming_soon' },
  { key: 'handover', icon: ShieldCheck, status: 'coming_soon' },
  { key: 'ai', icon: Sparkles, status: 'coming_soon' },
  { key: 'push', icon: Bell, status: 'coming_soon' },
];

export const AVAILABLE_FEATURES = FEATURES.filter((f) => f.status === 'available');
export const ROADMAP_FEATURES = FEATURES.filter((f) => f.status === 'coming_soon');

'use client';

import type { EntityMarkerData, Vec3, ViewerBundle, ViewerHandle } from '@bimdossier/viewer';
import { IfcViewer } from '@bimdossier/viewer/viewer-3d';
import { useTranslations } from 'next-intl';
import { useEffect, useRef, useState, type JSX } from 'react';

import { autoRotatePlugin } from './autoRotatePlugin';
import { cameraDebugPlugin } from './cameraDebugPlugin';
import { cameraZoomPlugin } from './cameraZoomPlugin';
import { DEMO_MODEL_ID, DEMO_SNAGS } from './demoSnags';
import { monochromeLookPlugin } from './monochromeLookPlugin';
import { snagPlacementPlugin, type SurfacePointsArgs } from './snagPlacementPlugin';

// Self-contained demo model: a static fragments file shipped in apps/web/public,
// so the marketing site has NO runtime dependency on the API or MinIO. The
// viewer's WASM + worker are likewise served from apps/web's own /public.
const DEMO_BUNDLE: ViewerBundle = {
  fragmentsUrl: '/models/demo.frag',
  modelId: DEMO_MODEL_ID,
  cacheKey: 'web-demo-frag-v2',
};

type Props = {
  /** When true, no idle auto-rotate (prefers-reduced-motion). */
  reducedMotion: boolean;
  /** Called on any load failure so the host can swap in the static fallback. */
  onError: () => void;
  /** Called once the model has loaded and markers are synced. */
  onLoaded?: () => void;
};

/**
 * The heavy half of the showcase — dynamically imported (`ssr:false`) so the
 * ~6 MB viewer chunk only loads when the section scrolls into view. Loads a
 * static, monochrome-rendered model with transparent background and the
 * hardcoded snag pins.
 *
 * It's a look-but-don't-edit hero: model-element selection + hover highlight
 * are disabled in `onReady`, so dragging/auto-rotate stay live but clicking the
 * building does nothing. The only interaction is the snag pins — clicking one
 * toggles a small card showing just its title.
 */
export default function SnagViewer({ reducedMotion, onError, onLoaded }: Props): JSX.Element {
  const t = useTranslations('snagShowcase');
  const handleRef = useRef<ViewerHandle | null>(null);
  const offClickRef = useRef<(() => void) | null>(null);
  const [activeSnagId, setActiveSnagId] = useState<string | null>(null);

  // Camera-tuning debug gate: on in dev, or on any build via `?camdebug`. Adds
  // the interaction-only `[snag-cam]` logger and enables wheel-zoom so you can
  // dolly the model to find `cameraZoomPlugin` knob values. Off → zero change
  // for real visitors (production keeps wheel disabled, no logger). SnagViewer
  // is `ssr:false`, so reading `window` here can't cause a hydration mismatch.
  const camDebug =
    process.env.NODE_ENV !== 'production' ||
    (typeof window !== 'undefined' && new URLSearchParams(window.location.search).has('camdebug'));

  // `sizeBoost` makes the model read bigger than a plain fit (distance ÷ boost).
  // The reveal is deferred until this framing lands (see onReady), so the model
  // appears already at this size — no zoom-in pop.
  const ZOOM = { sizeBoost: 1.5 } as const;
  const plugins = reducedMotion
    ? [monochromeLookPlugin(), cameraZoomPlugin({ ...ZOOM, animate: false }), snagPlacementPlugin()]
    : [monochromeLookPlugin(), cameraZoomPlugin(ZOOM), autoRotatePlugin(), snagPlacementPlugin()];
  if (camDebug) plugins.push(cameraDebugPlugin());

  // Dismiss the title card on Escape; tear down the marker-click subscription
  // on unmount.
  useEffect(() => {
    const onKey = (e: KeyboardEvent): void => {
      if (e.key === 'Escape') setActiveSnagId(null);
    };
    window.addEventListener('keydown', onKey);
    return () => {
      window.removeEventListener('keydown', onKey);
      offClickRef.current?.();
      offClickRef.current = null;
    };
  }, []);

  const activeSnag =
    activeSnagId !== null ? (DEMO_SNAGS.find((s) => s.id === activeSnagId) ?? null) : null;

  return (
    <div
      // Desktop only: pad the WebGL canvas 500px on the left so the model renders
      // toward the right (clearing the text overlaid on the left). Gated to `lg`
      // so it never pushes the model off a narrow phone screen — mobile stays
      // centered. The model itself is camera-centered (no focal offset).
      className="relative h-full w-full lg:[&_canvas]:pl-[500px]"
    >
      <IfcViewer
        // Forward the handle ref: `onReady` is only invoked once IfcViewer's
        // imperative handle exists, and React skips `useImperativeHandle`
        // entirely when no ref is forwarded. Without this, `onReady` never
        // fires — so `showcase.zoomIn` (the bigger framing), the marker sync,
        // and the selection/hover disable all silently no-op, leaving the model
        // at the small built-in `camera.zoomExtents` fit.
        ref={handleRef}
        bundle={DEMO_BUNDLE}
        className="h-full w-full"
        builtInPlugins="minimal"
        background={{ alpha: 0 }}
        shadows={{ enabled: false }}
        viewCube={{ enabled: false }}
        // Rotate-only turntable: drag rotates, panning + zoom are disabled. With
        // pan off the orbit target can never be knocked off the model center, so
        // the idle auto-rotate always spins around the building's center. wheel
        // 'none' keeps page scroll working over this full-bleed hero (camera-
        // controls bails on ACTION.NONE before preventDefault). Touch is locked
        // to rotate-only inside cameraZoomPlugin (the prop can't reach touch).
        controls={{ left: 'rotate', middle: 'none', right: 'none', wheel: 'none' }}
        plugins={plugins}
        onReady={async (handle) => {
          handleRef.current = handle;
          // Debug gate: expose the handle so you can re-run framing or read the
          // camera/model state from the console after editing knobs, e.g.
          // `__snagViewer.commands.execute('showcase.debug.snapshot')`.
          if (camDebug && typeof window !== 'undefined') {
            (window as unknown as { __snagViewer?: ViewerHandle }).__snagViewer = handle;
          }
          // Look, don't edit: disable model-element selection + hover highlight
          // so clicking/hovering the building paints nothing. Orbit/drag and the
          // idle auto-rotate are independent and stay live.
          await handle.commands.execute('selection.setEnabled', false).catch(() => undefined);
          await handle.commands.execute('hover.setEnabled', false).catch(() => undefined);
          // Frame the model in one self-contained move (center pivot + tilt +
          // zoom + right-shift). AWAITED so the reveal below only happens once
          // the showcase framing has landed — this is what hides the built-in
          // `camera.zoomExtents` excursion that runs just before onReady, so the
          // model fades in already framed instead of popping/zooming.
          await handle.commands.execute('showcase.zoomIn').catch(() => undefined);
          // Raycast well-spread points ON the framed model's surface, then pin
          // each snag to one (falling back to its authored coord if a probe
          // misses, so a pin is never dropped). This is what keeps the pins on
          // the building instead of floating at the old hardcoded coordinates.
          const points = await handle.commands
            .execute<Vec3[]>('showcase.surfacePoints', {
              count: DEMO_SNAGS.length,
              modelId: DEMO_MODEL_ID,
            } satisfies SurfacePointsArgs)
            .catch(() => [] as Vec3[]);
          const markers: EntityMarkerData[] = DEMO_SNAGS.map((snag, i) => ({
            id: snag.id,
            type: 'finding',
            position: points[i] ?? snag.position,
            modelId: DEMO_MODEL_ID,
            entityId: snag.id,
            status: snag.status,
            // Just the title — the pin keeps its status-colored real-app style,
            // and both the hover tooltip and the click card show only the title.
            label: t(`snags.${snag.titleKey}`),
          }));
          await handle.commands.execute('entity-marker.sync', markers).catch(() => undefined);
          // Clicking a pin toggles its title card (same id → dismiss).
          offClickRef.current = handle.events.on('entity-marker:click', (ev) => {
            setActiveSnagId((cur) => (cur === ev.id ? null : ev.id));
          });
          // Reveal on the next frame so the final framing is painted before the
          // host fades the canvas in (onLoaded → opacity 0→100).
          requestAnimationFrame(() => onLoaded?.());
        }}
        onError={onError}
      />

      {activeSnag !== null && (
        <div className="absolute bottom-4 right-4 z-10 flex max-w-[260px] items-start gap-2 rounded-lg bg-surface-low px-3 py-2 shadow-lg ring-1 ring-border">
          <span className="text-body3 font-medium text-foreground">
            {t(`snags.${activeSnag.titleKey}`)}
          </span>
          <button
            type="button"
            aria-label={t('dismissSnag')}
            onClick={() => setActiveSnagId(null)}
            className="-mr-1 -mt-0.5 shrink-0 rounded p-0.5 text-body3 text-foreground-tertiary transition-colors hover:text-foreground"
          >
            <span aria-hidden>✕</span>
          </button>
        </div>
      )}
    </div>
  );
}

import type { Plugin, ViewerContext } from '@bimdossier/viewer';

export type AutoRotateOptions = {
  /** Azimuth radians per second. Default 0.18 — a slow turntable. */
  speed?: number;
  /** Resume this many ms after the user stops dragging. Default 2000. */
  resumeDelayMs?: number;
};

/**
 * Gentle idle auto-rotate for the marketing 3D showcase. The viewer renders
 * on-demand (parks in MANUAL mode when idle), so each frame advances the camera
 * azimuth and calls `ctx.requestRender()` to wake it. Spinning pauses while the
 * user is dragging (camera-controls `controlstart`), resuming after a short idle
 * so manual orbit always wins — merely hovering the model never stops the spin.
 * The `auto-rotate.setPaused` command lets another plugin freeze the turntable
 * for a transient operation that needs a fixed pose (snagPlacementPlugin holds it
 * still while raycasting snag positions, then resumes). Registered through
 * `<IfcViewer plugins={[...]}>`; omit it entirely to disable (e.g.
 * `prefers-reduced-motion`).
 */
export function autoRotatePlugin(options: AutoRotateOptions = {}): Plugin {
  const speed = options.speed ?? 0.18;
  const resumeDelayMs = options.resumeDelayMs ?? 2000;

  let ctx: ViewerContext | null = null;
  let raf = 0;
  let last = 0;
  // Held by another plugin via `auto-rotate.setPaused` to freeze the turntable
  // for a transient fixed-pose operation (e.g. snag-placement raycasting).
  let externallyPaused = false;
  let interacting = false;
  let resumeTimer: ReturnType<typeof setTimeout> | null = null;
  const onStart = (): void => {
    interacting = true;
    if (resumeTimer) {
      clearTimeout(resumeTimer);
      resumeTimer = null;
    }
  };
  const onEnd = (): void => {
    if (resumeTimer) clearTimeout(resumeTimer);
    resumeTimer = setTimeout(() => {
      interacting = false;
    }, resumeDelayMs);
  };

  const tick = (now: number): void => {
    raf = requestAnimationFrame(tick);
    const dt = last ? (now - last) / 1000 : 0;
    last = now;
    if (ctx === null || externallyPaused || interacting || dt <= 0) return;
    // Azimuth only → a clean turntable. Fire-and-forget, then wake the renderer.
    void ctx.cameraControls.rotate(speed * dt, 0, false);
    ctx.requestRender();
  };

  return {
    name: 'auto-rotate',
    install(context: ViewerContext): void {
      ctx = context;
      context.cameraControls.addEventListener('controlstart', onStart);
      context.cameraControls.addEventListener('controlend', onEnd);
      context.commands.register(
        'auto-rotate.setPaused',
        (args: unknown) => {
          externallyPaused = Boolean((args as { paused?: boolean } | undefined)?.paused);
        },
        { title: 'Pause or resume idle auto-rotate' },
      );
      last = 0;
      raf = requestAnimationFrame(tick);
    },
    uninstall(): void {
      cancelAnimationFrame(raf);
      if (resumeTimer) clearTimeout(resumeTimer);
      if (ctx !== null) {
        ctx.cameraControls.removeEventListener('controlstart', onStart);
        ctx.cameraControls.removeEventListener('controlend', onEnd);
      }
      ctx = null;
    },
  };
}

import type { Plugin, ViewerContext } from '@bimdossier/viewer';

type Vec3Like = { x: number; y: number; z: number };

const r3 = (n: number): number => Math.round(n * 1000) / 1000;
const v3 = (v: Vec3Like): Vec3Like => ({ x: r3(v.x), y: r3(v.y), z: r3(v.z) });

/**
 * Debug-only camera/model logger for the marketing 3D showcase. Sibling of
 * `autoRotatePlugin` / `cameraZoomPlugin`; wired into `<SnagViewer>`'s plugin
 * array only behind a dev/`?camdebug` gate, so it never ships to visitors.
 *
 * Purpose: dial in "bigger + shifted right" WITHOUT guessing. The showcase look
 * is relative knobs on `cameraZoomPlugin` (`factorWide`, `panFraction`, plus
 * `polarDeg`/`azimuthDeg`) — responsive by construction, not an absolute camera
 * pose. On each user interaction this prints the raw camera/model state AND the
 * *derived* knob values, so you orbit to taste and paste the numbers straight in.
 *
 * Why a plugin and not a `handle.events` subscription in SnagViewer:
 *   - The user-only `controlstart`/`controlend` events live on
 *     `ctx.cameraControls`, which isn't exposed through `ViewerHandle`. Idle
 *     auto-rotate moves the camera via `cameraControls.rotate(...)` — that fires
 *     camera-controls' `update` (and the viewer's `camera:change`) but NOT
 *     `controlend`. So logging on `controlend` is silent during the spin and
 *     fires only on real drag — exactly the requirement.
 */
export function cameraDebugPlugin(): Plugin {
  let ctx: ViewerContext | null = null;

  const snapshot = (label: string): void => {
    if (ctx === null) return;
    const cc = ctx.cameraControls;

    // No `three` import (matches the sibling plugins) — clone the camera's own
    // Vector3 as scratch for the out-param getters.
    const target = cc.getTarget(ctx.camera.position.clone());
    const focalOffset = cc.getFocalOffset(ctx.camera.position.clone());
    const distance = cc.distance;
    const wide = typeof window !== 'undefined' && window.innerWidth >= 1024;

    // Perspective fov maths — same as cameraZoomPlugin, so the derived knobs
    // invert its formulas exactly.
    const cam = ctx.camera as unknown as { isPerspectiveCamera?: boolean; fov?: number; aspect?: number };
    const persp = Boolean(cam.isPerspectiveCamera) && !!cam.fov && !!cam.aspect;
    const halfV = persp ? ((cam.fov as number) * Math.PI) / 180 / 2 : NaN;
    const halfH = persp ? Math.atan(Math.tan(halfV) * (cam.aspect as number)) : NaN;
    const tanH = persp ? Math.tan(halfH) : NaN;

    // Union of every loaded model's world AABB → center / size / radius.
    let minX = Infinity;
    let minY = Infinity;
    let minZ = Infinity;
    let maxX = -Infinity;
    let maxY = -Infinity;
    let maxZ = -Infinity;
    let any = false;
    for (const m of ctx.models().values()) {
      const b = m.box;
      if (!b || b.isEmpty()) continue;
      any = true;
      minX = Math.min(minX, b.min.x);
      minY = Math.min(minY, b.min.y);
      minZ = Math.min(minZ, b.min.z);
      maxX = Math.max(maxX, b.max.x);
      maxY = Math.max(maxY, b.max.y);
      maxZ = Math.max(maxZ, b.max.z);
    }
    const size: Vec3Like = { x: maxX - minX, y: maxY - minY, z: maxZ - minZ };
    const radius = Math.hypot(size.x, size.y, size.z) / 2;
    const model = any
      ? {
          center: v3({ x: (minX + maxX) / 2, y: (minY + maxY) / 2, z: (minZ + maxZ) / 2 }),
          size: v3(size),
          radius: r3(radius),
        }
      : null;

    // Auto-fit distance D0 (same as cameraZoomPlugin): fits the bounding sphere
    // in the limiting (smaller) half-angle. The knobs are relative to this.
    const d0 = persp && any && radius > 0 ? radius / Math.sin(Math.min(halfV, halfH)) : NaN;
    const okD0 = Number.isFinite(d0) && d0 > 0;

    // Derived cameraZoomPlugin knobs:
    //   factorWide: zoomIn dollies to D0*(1-f), so f = 1 - distance/D0.
    //   panFraction == on-screen shift (focal offset sized against final distance).
    const factorWide = okD0 ? r3(1 - distance / (d0 as number)) : null;
    const screenShiftFraction =
      Number.isFinite(tanH) && tanH !== 0 ? r3(-focalOffset.x / (distance * tanH)) : null;
    const panFraction = screenShiftFraction;

    // eslint-disable-next-line no-console
    console.log(`[snag-cam] ${label}`, {
      position: v3(ctx.camera.position),
      target: v3(target),
      distance: r3(distance),
      focalOffset: v3(focalOffset),
      zoom: r3(ctx.camera.zoom),
      azimuthDeg: r3((cc.azimuthAngle * 180) / Math.PI),
      polarDeg: r3((cc.polarAngle * 180) / Math.PI),
      branch: wide ? 'wide (desktop)' : 'narrow (mobile)',
      model,
      // ↓ Paste these into cameraZoomPlugin({ ... }) in SnagViewer.tsx.
      suggestedKnobs: {
        factorWide, // → factorWide (desktop) / factor (mobile)
        panFraction, // → panFraction (desktop right-shift)
        polarDeg: r3((cc.polarAngle * 180) / Math.PI), // → polarDeg (tilt)
        azimuthDeg: r3((cc.azimuthAngle * 180) / Math.PI), // → azimuthDeg (facing)
        fitDistance: okD0 ? r3(d0 as number) : '(no perspective/model yet)',
      },
    });
  };

  const onControlEnd = (): void => snapshot('interaction end');

  return {
    name: 'showcase-camera-debug',
    install(context: ViewerContext): void {
      ctx = context;
      // User-only: fires on drag release, never during programmatic spin.
      context.cameraControls.addEventListener('controlend', onControlEnd);
      // On-demand snapshot (e.g. to read the framed pose without dragging).
      context.commands.register('showcase.debug.snapshot', () => snapshot('snapshot'), {
        title: 'Log the current showcase camera + model state',
      });
    },
    uninstall(): void {
      if (ctx !== null) {
        ctx.cameraControls.removeEventListener('controlend', onControlEnd);
      }
      ctx = null;
    },
  };
}

import type { Plugin, ViewerContext } from '@bimdossier/viewer';

export type CameraZoomOptions = {
  /**
   * Dolly fraction on narrow (mobile) screens, where the model is centered.
   * Positive = closer/bigger, as a fraction of the auto-fit distance. Default 0.2.
   */
  factor?: number;
  /**
   * Dolly fraction on wide (desktop) screens. Positive = closer/bigger. Default
   * 0.3 — the model reads clearly larger than a plain fit while still clearing
   * the text overlaid on the left.
   */
  factorWide?: number;
  /**
   * Animate the camera move. Default FALSE — the model just appears already
   * framed, then the idle turntable takes over. Instant framing is robust: it
   * lands before the auto-rotate starts spinning (an animated transition can be
   * snapped by the per-frame `cc.rotate`), and it doesn't depend on rAF.
   */
  animate?: boolean;
  /**
   * Extra "make it bigger" multiplier on top of the dolly framing — the model's
   * on-screen size is scaled by this (distance ÷ sizeBoost). Default 1.2 (20%
   * bigger). The right-shift is NOT done here: it's a CSS `padding-left` on the
   * canvas in SnagViewer (desktop only), so the model stays camera-centered and
   * the focal offset is always cleared.
   */
  sizeBoost?: number;
  /**
   * Camera tilt in degrees (polar angle: 0 = top-down, 90 = dead-on side).
   * Default 90 — dead-level, looking at the building straight from the side.
   */
  polarDeg?: number;
  /**
   * Horizontal facing in degrees (azimuth). Default 45 — a 3/4 corner view. The
   * idle turntable spins this, so it only sets the first frame.
   */
  azimuthDeg?: number;
};

/** camera-controls `ACTION` enum, read off the controls' constructor so we don't
 *  import the library (keeps this plugin dependency-free like its siblings). */
type ActionEnum = Record<string, number>;
const actionEnum = (cc: unknown): ActionEnum | null =>
  (cc as { constructor?: { ACTION?: ActionEnum } }).constructor?.ACTION ?? null;

type Box = { min: { x: number; y: number; z: number }; max: { x: number; y: number; z: number } };

/**
 * Marketing-showcase camera setup. The built-in `camera` plugin only frames the
 * model centered with a fixed padding; this plugin tailors that into the hero
 * look and locks the controls to a rotate-only turntable.
 *
 * `showcase.zoomIn` (issued once in `onReady`) frames the model in a SINGLE,
 * self-contained move computed from the model's world box — it does NOT depend on
 * a prior `camera.zoomExtents` settling (awaiting that animated command is
 * fragile: if it resolves before the box is ready, or its transition is
 * interrupted, the refinement never lands and the model shows the raw centered
 * framing). It:
 *   - puts the orbit TARGET on the model center (so the idle auto-rotate spins
 *     the model about its own center);
 *   - places the eye at `polarDeg` tilt / `azimuthDeg` facing, at a distance that
 *     fits the model then dollies in by `factorWide`/`factor` × `sizeBoost`
 *     (bigger); the model stays CAMERA-CENTERED (focal offset always 0).
 *
 * The right-shift is done in CSS (a `padding-left` on the canvas, desktop only —
 * see SnagViewer), not the camera, so it never pushes the model off a phone
 * screen and the turntable keeps spinning about the model's own center.
 *
 * `install` also locks TOUCH input to one-finger-rotate only (two/three-finger =
 * none), disabling pinch-zoom and two-finger pan on mobile. Mouse buttons are
 * locked to rotate-only via the `<IfcViewer controls>` prop in SnagViewer (the
 * prop covers mouse but not touch — hence the touch lock here).
 */
export function cameraZoomPlugin(options: CameraZoomOptions = {}): Plugin {
  const factor = options.factor ?? 0.2;
  const factorWide = options.factorWide ?? 0.3;
  const animate = options.animate ?? false;
  const sizeBoost = options.sizeBoost ?? 1.2;
  const polarRad = ((options.polarDeg ?? 90) * Math.PI) / 180;
  const azimuthRad = ((options.azimuthDeg ?? 45) * Math.PI) / 180;

  let ctx: ViewerContext | null = null;
  let offModelLoaded: (() => void) | null = null;

  return {
    name: 'showcase-camera-zoom',
    install(context: ViewerContext): void {
      ctx = context;

      // Rotate-only on touch: one finger orbits, two/three fingers do nothing
      // (no pinch-zoom, no two-finger pan). Mirrors the mouse lock set via the
      // controls prop, which can't reach touch.
      const cc = context.cameraControls as unknown as {
        touches: { one: number; two: number; three: number };
      };
      const ACTION = actionEnum(context.cameraControls);
      if (ACTION) {
        cc.touches.one = ACTION['TOUCH_ROTATE'] ?? cc.touches.one;
        cc.touches.two = ACTION['NONE'] ?? cc.touches.two;
        cc.touches.three = ACTION['NONE'] ?? cc.touches.three;
      }

      const frame = async (): Promise<void> => {
          if (ctx === null) return;
          const controls = ctx.cameraControls;
          const box = await ctx.commands.execute<undefined, Box | null>('camera.getSceneBox');
          if (!box) return;

          // Model center + bounding-sphere radius.
          const cx = (box.min.x + box.max.x) / 2;
          const cy = (box.min.y + box.max.y) / 2;
          const cz = (box.min.z + box.max.z) / 2;
          const r =
            Math.hypot(box.max.x - box.min.x, box.max.y - box.min.y, box.max.z - box.min.z) / 2;
          if (r <= 0) return;

          const wide = typeof window !== 'undefined' && window.innerWidth >= 1024;
          const cam = ctx.camera as unknown as { fov: number; aspect: number };
          const halfV = ((cam.fov ?? 60) * Math.PI) / 180 / 2;
          const halfH = Math.atan(Math.tan(halfV) * (cam.aspect ?? 1));
          // Distance that fits the sphere in the limiting (smaller) half-angle.
          const fitHalf = Math.min(halfV, halfH);
          const d0 = r / Math.sin(fitHalf);
          const f = wide ? factorWide : factor;
          // Dolly in by the framing fraction, then divide by sizeBoost so the
          // model reads `sizeBoost`× bigger (1.12 → +12%).
          const dd = (d0 * (1 - f)) / sizeBoost;

          // Eye on the (azimuth, polar) sphere around the center, distance dd.
          // camera-controls / three Spherical, Y-up:
          //   x = sinφ·sinθ, y = cosφ, z = sinφ·cosθ.
          const sinP = Math.sin(polarRad);
          const ex = cx + dd * sinP * Math.sin(azimuthRad);
          const ey = cy + dd * Math.cos(polarRad);
          const ez = cz + dd * sinP * Math.cos(azimuthRad);
          void controls.setLookAt(ex, ey, ez, cx, cy, cz, animate);
          // Keep the model camera-centered; the right-shift is the CSS
          // padding-left on the canvas (SnagViewer, desktop only).
          void controls.setFocalOffset(0, 0, 0, animate);

          ctx.requestRender();
      };

      context.commands.register('showcase.zoomIn', frame, {
        title: 'Frame the showcase camera (center pivot + tilt + zoom)',
      });

      // Frame on every model load. `model:loaded` is emitted inside the viewer's
      // loadFragments AFTER its built-in centered `frameModel`, so framing here
      // reliably overrides that fit — and unlike the host's `onReady`, it always
      // runs (no race, survives the streaming model load) and re-applies on any
      // remount. This is what actually makes the tilt/zoom stick.
      offModelLoaded = context.events.on('model:loaded', () => {
        void frame();
      });
    },
    uninstall(): void {
      offModelLoaded?.();
      offModelLoaded = null;
      ctx = null;
    },
  };
}

import type { Plugin, ViewerContext, Vec3 } from '@bimdossier/viewer';
import { pick } from '@bimdossier/viewer/viewer-3d';

export type SurfacePointsArgs = {
  /** How many spread-out surface points to return. */
  count: number;
  /** Scene id of the model to raycast (matches the marker's `modelId`). */
  modelId: string;
};

// Central NDC probe grid, tuned to the showcase's 3/4-corner framing (azimuth
// 45°, polar 90°, sizeBoost 1.5 — see cameraZoomPlugin). Kept well inside the
// frame (|x| ≤ 0.28 / |y| ≤ 0.24) so every sample lands on the building's
// silhouette; samples that miss the model are simply dropped. NDC is relative to
// the canvas and the model is camera-centered, so this is screen-size agnostic.
const NDC_XS = [-0.28, -0.14, 0, 0.14, 0.28] as const;
const NDC_YS = [0.24, 0.08, -0.08, -0.24] as const;

const dist = (a: Vec3, b: Vec3): number => Math.hypot(a.x - b.x, a.y - b.y, a.z - b.z);

const byCoord = (a: Vec3, b: Vec3): number => a.x - b.x || a.y - b.y || a.z - b.z;

/**
 * Greedy farthest-point selection: deterministically pick `count` points that
 * are maximally spread out, so no two snag pins cluster on the same flat wall.
 * Seeded from the lowest (x,y,z) hit so the result is stable across reloads.
 */
function spread(points: Vec3[], count: number): Vec3[] {
  if (points.length <= count) return points;
  const remaining = [...points].sort(byCoord);
  const chosen: Vec3[] = [remaining.shift() as Vec3];
  while (chosen.length < count && remaining.length > 0) {
    let bestIdx = 0;
    let bestMin = -Infinity;
    for (let i = 0; i < remaining.length; i++) {
      const p = remaining[i] as Vec3;
      let minD = Infinity;
      for (const c of chosen) minD = Math.min(minD, dist(p, c));
      if (minD > bestMin) {
        bestMin = minD;
        bestIdx = i;
      }
    }
    chosen.push(remaining.splice(bestIdx, 1)[0] as Vec3);
  }
  return chosen;
}

/**
 * Marketing-showcase snag placement. Sibling of `autoRotatePlugin` /
 * `cameraZoomPlugin` — registers `showcase.surfacePoints`, which raycasts the
 * loaded demo model and returns up to `count` well-spread points that sit ON its
 * surface (in the model's LOCAL frame, the frame `entity-marker` expects).
 *
 * SnagViewer calls it once in `onReady` after `showcase.zoomIn` frames the
 * model, then pins the demo snags to the returned points. This replaces the old
 * hand-authored coordinates, which fell inside the bounding-box *volume* (empty
 * interior/air) and so projected as "floating" pins beside the building — the
 * CSS2D marker overlay does not depth-test, so an off-geometry anchor just
 * projects to wherever it lands on screen. On-surface points stay inside the
 * silhouette from every angle as the model auto-rotates.
 */
export function snagPlacementPlugin(): Plugin {
  let ctx: ViewerContext | null = null;

  const surfacePoints = async (args: unknown): Promise<Vec3[]> => {
    if (ctx === null) return [];
    const { count, modelId } = (args as SurfacePointsArgs | undefined) ?? {
      count: 0,
      modelId: '',
    };
    if (count <= 0) return [];

    // Pause the idle turntable so every probe samples the same framed pose
    // (no-op under reduced-motion — the command isn't registered), and flush any
    // pending `setLookAt` onto the camera so the raycast uses that pose.
    await ctx.commands.execute('auto-rotate.setPaused', { paused: true }).catch(() => undefined);
    ctx.cameraControls.update(0);

    const hits: Vec3[] = [];
    for (const x of NDC_XS) {
      for (const y of NDC_YS) {
        const hit = await pick(ctx, { x, y });
        if (hit) hits.push(hit.point);
      }
    }

    await ctx.commands.execute('auto-rotate.setPaused', { paused: false }).catch(() => undefined);

    if (hits.length === 0) return [];

    const chosen = spread(hits, count);

    // pick() returns WORLD-space points; entity-marker re-applies the model's
    // world matrix at render time, so hand back LOCAL-frame points (its inverse).
    // Identity for the single base model, but correct if coordination ever
    // shifts. Borrow the camera's Vector3 as scratch (no `three` import — matches
    // the sibling plugins).
    const obj = ctx.models().get(modelId)?.object ?? null;
    obj?.updateWorldMatrix(true, false);
    const inv = obj ? obj.matrixWorld.clone().invert() : null;
    const toLocal = (p: Vec3): Vec3 => {
      if (ctx === null || inv === null) return p;
      const v = ctx.camera.position.clone();
      v.set(p.x, p.y, p.z).applyMatrix4(inv);
      return { x: v.x, y: v.y, z: v.z };
    };

    // Stable left→right ordering so each snag tends to the same area on reload.
    return chosen.map(toLocal).sort(byCoord);
  };

  return {
    name: 'showcase-snag-placement',
    install(context: ViewerContext): void {
      ctx = context;
      context.commands.register('showcase.surfacePoints', surfacePoints, {
        title: 'Raycast well-spread on-surface points for the demo snags',
      });
    },
    uninstall(): void {
      ctx = null;
    },
  };
}

import { useId, type JSX } from 'react';

type Props = {
  cellSize?: number;
  className?: string;
  toneClassName?: string;
};

/**
 * Blueprint grid texture — a token-faithful port of the portal's
 * `BlueprintTexture`. Uses `currentColor` + a Tailwind tone class so the line
 * color comes from the design tokens and adapts to light/dark automatically
 * (never a raw hex). Opacity is left to the caller via `className`
 * (e.g. `opacity-[0.06]`) so the same primitive works as a card wash or a
 * placeholder backdrop. Absolutely positioned — the parent needs
 * `relative overflow-hidden`.
 */
export function BlueprintTexture({
  cellSize = 32,
  className,
  toneClassName = 'text-primary',
}: Props): JSX.Element {
  const patternId = useId();

  return (
    <svg
      width="100%"
      height="100%"
      className={`pointer-events-none absolute inset-0 ${className ?? ''}`}
      aria-hidden="true"
    >
      <defs>
        <pattern
          id={patternId}
          width={cellSize}
          height={cellSize}
          patternUnits="userSpaceOnUse"
        >
          <path
            d={`M ${cellSize} 0 L 0 0 0 ${cellSize}`}
            fill="none"
            stroke="currentColor"
            strokeWidth="0.6"
            className={toneClassName}
          />
        </pattern>
      </defs>
      <rect width="100%" height="100%" fill={`url(#${patternId})`} />
    </svg>
  );
}

'use client';

import type { JSX, ReactNode } from 'react';

import { useInView } from '@/hooks/useInView';
import { useReducedMotion } from '@/hooks/useReducedMotion';

type RevealProps = {
  children: ReactNode;
  /** Stagger delay in ms (e.g. `index * 80` for a cascade). */
  delay?: number;
  className?: string;
};

/**
 * Fade + 16px rise as the element scrolls into view. Dependency-free
 * (IntersectionObserver + a CSS transition), GPU-friendly (only opacity +
 * transform, so no layout thrash — the element holds its final box throughout).
 * `prefers-reduced-motion` shows the content immediately with no transform, both
 * via the `motion-reduce` Tailwind variant and the hook (belt and suspenders).
 */
export function Reveal({ children, delay = 0, className }: RevealProps): JSX.Element {
  const reducedMotion = useReducedMotion();
  const { ref, inView } = useInView<HTMLDivElement>({ once: true });
  const visible = reducedMotion || inView;

  return (
    <div
      ref={ref}
      data-state={visible ? 'visible' : 'hidden'}
      style={delay > 0 && !reducedMotion ? { transitionDelay: `${delay}ms` } : undefined}
      className={[
        'transition-[opacity,transform] duration-700 ease-out',
        'data-[state=hidden]:translate-y-4 data-[state=hidden]:opacity-0',
        'data-[state=visible]:translate-y-0 data-[state=visible]:opacity-100',
        'motion-reduce:translate-y-0 motion-reduce:opacity-100 motion-reduce:transition-none',
        className ?? '',
      ].join(' ')}
    >
      {children}
    </div>
  );
}

import { Eyebrow, cn } from '@bimdossier/ui';
import type { JSX } from 'react';

type SectionHeadingProps = {
  eyebrow: string;
  headline: string;
  subtitle?: string;
  /** Extra classes for the wrapper (e.g. override the default `mb-12`). */
  className?: string;
};

/**
 * Centered marketing section header: eyebrow + h2 + optional subtitle, vertically
 * stacked and centered. Extracted from the verbatim cluster that repeated across
 * the home-page sections. Data flows in via props only (store-agnostic).
 */
export function SectionHeading({
  eyebrow,
  headline,
  subtitle,
  className,
}: SectionHeadingProps): JSX.Element {
  return (
    <div className={cn('mb-12 flex flex-col items-center gap-3 text-center', className)}>
      <Eyebrow size="sm">{eyebrow}</Eyebrow>
      <h2 className="max-w-2xl text-h3 font-semibold text-foreground">{headline}</h2>
      {subtitle ? (
        <p className="max-w-xl text-body1 text-foreground-secondary">{subtitle}</p>
      ) : null}
    </div>
  );
}

'use client';

import { useEffect, useRef, useState, type RefObject } from 'react';

type UseInViewOptions = {
  threshold?: number;
  rootMargin?: string;
  /** Stop observing after the first reveal (default true). */
  once?: boolean;
};

/**
 * Reveal-on-scroll primitive. Attaches one `IntersectionObserver` to the
 * returned ref; when the element enters the viewport `inView` flips true and
 * (when `once`) the observer disconnects immediately — no lingering observers.
 * Falls back to `inView: true` when `IntersectionObserver` is unavailable so
 * content is never hidden (progressive enhancement, content-first).
 */
export function useInView<T extends Element = HTMLDivElement>(
  options: UseInViewOptions = {},
): { ref: RefObject<T | null>; inView: boolean } {
  const { threshold = 0.15, rootMargin = '0px 0px -10% 0px', once = true } = options;
  const ref = useRef<T | null>(null);
  const [inView, setInView] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (el === null) return undefined;
    if (typeof IntersectionObserver === 'undefined') {
      setInView(true);
      return undefined;
    }
    const observer = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (entry.isIntersecting) {
            setInView(true);
            if (once) observer.disconnect();
          } else if (!once) {
            setInView(false);
          }
        }
      },
      { threshold, rootMargin },
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [threshold, rootMargin, once]);

  return { ref, inView };
}

'use client';

import { useEffect, useState } from 'react';

/**
 * Tracks the user's `prefers-reduced-motion` setting. SSR-safe: starts `false`
 * (motion allowed) and resolves on mount, so the server and first client render
 * agree. Mirrors the `matchMedia` + `change`-listener idiom used elsewhere in
 * the monorepo (e.g. apps/portal `useIsMobile`).
 */
export function useReducedMotion(): boolean {
  const [reduced, setReduced] = useState(false);

  useEffect(() => {
    const mq = window.matchMedia('(prefers-reduced-motion: reduce)');
    setReduced(mq.matches);
    const onChange = (event: MediaQueryListEvent): void => setReduced(event.matches);
    mq.addEventListener('change', onChange);
    return () => mq.removeEventListener('change', onChange);
  }, []);

  return reduced;
}

